import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { FaHome, FaUsers, FaBook, FaBuilding, FaChalkboardTeacher, FaCalendarAlt, FaCog } from 'react-icons/fa';

const Navbar = () => {
  const location = useLocation();

  const navItems = [
    { path: '/', label: 'Dashboard', icon: <FaHome /> },
    { path: '/students', label: 'Students', icon: <FaUsers /> },
    { path: '/subjects', label: 'Subjects', icon: <FaBook /> },
    { path: '/halls', label: 'Halls', icon: <FaBuilding /> },
    { path: '/teachers', label: 'Teachers', icon: <FaChalkboardTeacher /> },
    { path: '/generate', label: 'Generate', icon: <FaCog /> },
    { path: '/schedule', label: 'Schedule', icon: <FaCalendarAlt /> },
  ];

  return (
    <nav className="gradient-bg shadow-lg">
      <div className="container mx-auto px-4">
        <div className="flex items-center justify-between py-4">
          <Link to="/" className="flex items-center space-x-2">
            <FaCalendarAlt className="text-white text-2xl" />
            <span className="text-white text-xl font-bold">Smart Exam Scheduler</span>
          </Link>

          <div className="flex space-x-1">
            {navItems.map((item) => (
              <Link
                key={item.path}
                to={item.path}
                className={`flex items-center space-x-2 px-4 py-2 rounded-lg transition duration-200 ${
                  location.pathname === item.path
                    ? 'bg-white bg-opacity-20 text-white'
                    : 'text-white hover:bg-white hover:bg-opacity-10'
                }`}
              >
                {item.icon}
                <span className="hidden md:inline">{item.label}</span>
              </Link>
            ))}
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
